def get_base_path():
    if getattr(sys, 'frozen', False):
        return Path(sys.executable).parent
    else:
        return Path(__file__).parent

class StyleManager:
    STYLE_DIR = get_base_path() / "style"
    CONFIG_FILE = STYLE_DIR / "theme_config.json"
    DEFAULT_THEME = "clam"
    DEFAULT_BG_COLOR = "#f0f3f5"
    DEFAULT_FG_COLOR = "#2c3e50"

    @classmethod
    def ensure_style_dir(cls):
        if not cls.STYLE_DIR.exists():
            cls.STYLE_DIR.mkdir(parents=True, exist_ok=True)

    @classmethod
    def load_config(cls):
        cls.ensure_style_dir()
        if cls.CONFIG_FILE.exists():
            try:
                with open(cls.CONFIG_FILE, "r", encoding="utf-8") as f:
                    config = json.load(f)
                    if "theme" in config and "bg_color" in config and "fg_color" in config:
                        return config
            except Exception:
                pass
        return {"theme": cls.DEFAULT_THEME, "bg_color": cls.DEFAULT_BG_COLOR, "fg_color": cls.DEFAULT_FG_COLOR}

    @classmethod
    def save_config(cls, theme, bg_color, fg_color):
        cls.ensure_style_dir()
        config = {"theme": theme, "bg_color": bg_color, "fg_color": fg_color}
        try:
            with open(cls.CONFIG_FILE, "w", encoding="utf-8") as f:
                json.dump(config, f, indent=4, ensure_ascii=False)
            return True
        except Exception as e:
            print(f"保存配置失败: {e}")
            return False

class ApkEditorRunner:
    def __init__(self, root):
        self.root = root
        self.root.title("HTML打包APK工具")
        self.root.geometry("640x490")  # 增加高度以容纳状态标签
        self.root.resizable(False, False)

        self.style_config = StyleManager.load_config()
        self.current_theme = self.style_config["theme"]
        self.current_bg = self.style_config["bg_color"]
        self.current_fg = self.style_config["fg_color"]

        self.set_window_icon()

        base_path = get_base_path()
        self.exe_path_editor = base_path / "apkEditor" / "apkEditor_2.exe"
        self.exe_path_studio = base_path / "apkEditorStudio" / "apk-editor-studio.exe"
        tools_dir = base_path / "apkEditorStudio" / "tools"
        self.apktool_jar = tools_dir / "apktool.jar"
        self.apksigner_jar = tools_dir / "apksigner.jar"
        self.zipalign_exe = tools_dir / "zipalign.exe"

        self.temp_dir = Path(tempfile.gettempdir()) / "html_to_apk_temp"
        self.temp_dir.mkdir(exist_ok=True)
        self.java_exe = None

        self.setup_styles()
        self.create_widgets()
        self.check_dependencies()

        self.selected_permissions = None
        self.permission_configured = False

    def setup_styles(self):
        style = ttk.Style()
        try:
            available_themes = style.theme_names()
            if self.current_theme in available_themes:
                style.theme_use(self.current_theme)
            else:
                style.theme_use('clam')
                self.current_theme = 'clam'
        except:
            style.theme_use('clam')
            self.current_theme = 'clam'

        bg_color = self.current_bg
        fg_color = self.current_fg
        entry_bg = 'white'

        style.configure('.', background=bg_color, foreground=fg_color, font=('微软雅黑', 8))
        style.configure('TLabel', background=bg_color, foreground=fg_color, font=('微软雅黑', 8))
        style.configure('TLabelframe', background=bg_color, font=('微软雅黑', 9, 'bold'))
        style.configure('TLabelframe.Label', background=bg_color, foreground=fg_color, font=('微软雅黑', 9, 'bold'))
        style.configure('TEntry', fieldbackground=entry_bg, foreground=fg_color, font=('微软雅黑', 8))
        style.configure('TButton', font=('微软雅黑', 8))
        style.configure('TCheckbutton', background=bg_color, foreground=fg_color, font=('微软雅黑', 8),
                        indicatorcolor=bg_color, indicatormargin=2)
        style.map('TCheckbutton', indicatorbackground=[('selected', '#0078D7'), ('!selected', 'white')],
                  indicatorforeground=[('selected', 'white'), ('!selected', fg_color)])
        style.configure('TFrame', background=bg_color)
        style.configure('Accent.TButton', background='#0078D7', foreground='black')
        style.map('Accent.TButton', background=[('active', '#005a9e')], foreground=[('active', 'black')])

        self.root.configure(bg=bg_color)

    def apply_style(self, theme, bg_color, fg_color):
        self.current_theme = theme
        self.current_bg = bg_color
        self.current_fg = fg_color
        style = ttk.Style()
        try:
            style.theme_use(theme)
        except:
            style.theme_use('clam')
            self.current_theme = 'clam'

        bg_color = self.current_bg
        fg_color = self.current_fg
        entry_bg = 'white'

        style.configure('.', background=bg_color, foreground=fg_color, font=('微软雅黑', 8))
        style.configure('TLabel', background=bg_color, foreground=fg_color, font=('微软雅黑', 8))
        style.configure('TLabelframe', background=bg_color, font=('微软雅黑', 9, 'bold'))
        style.configure('TLabelframe.Label', background=bg_color, foreground=fg_color, font=('微软雅黑', 9, 'bold'))
        style.configure('TEntry', fieldbackground=entry_bg, foreground=fg_color, font=('微软雅黑', 8))
        style.configure('TButton', font=('微软雅黑', 8))
        style.configure('TCheckbutton', background=bg_color, foreground=fg_color, font=('微软雅黑', 8),
                        indicatorcolor=bg_color, indicatormargin=2)
        style.map('TCheckbutton', indicatorbackground=[('selected', '#0078D7'), ('!selected', 'white')],
                  indicatorforeground=[('selected', 'white'), ('!selected', fg_color)])
        style.configure('TFrame', background=bg_color)
        style.configure('Accent.TButton', background='#0078D7', foreground='black')
        style.map('Accent.TButton', background=[('active', '#005a9e')], foreground=[('active', 'black')])

        self.root.configure(bg=bg_color)
